n = int(input()) * 2
s = input().strip()
mod = 10**9 + 7

# Preprocess the automaton transitions
m = len(s)
d = {}
for k in range(m + 1):
    for c in ['(', ')']:
        # Find the longest prefix of s that is a suffix of s[:k] + c
        max_match = min(k + 1, m)
        while max_match > 0:
            if s[:max_match] == (s[:k] + c)[-max_match:]:
                break
            max_match -= 1
        d[(k, c)] = max_match

# Initialize DP table
dp = [[[0] * (m + 1) for _ in range(n // 2 + 2)] for __ in range(n + 1)]
dp[0][0][0] = 1

for i in range(n):
    for j in range(n // 2 + 1):
        for k in range(m + 1):
            if dp[i][j][k] == 0:
                continue
            # Add ')'
            if j > 0:
                new_k = d[(k, ')')]
                dp[i + 1][j - 1][new_k] = (dp[i + 1][j - 1][new_k] + dp[i][j][k]) % mod
            # Add '('
            if j + 1 <= n // 2:
                new_k = d[(k, '(')]
                dp[i + 1][j + 1][new_k] = (dp[i + 1][j + 1][new_k] + dp[i][j][k]) % mod

print(dp[n][0][m] % mod)
